// Data types for the API

import {descriptionToSteps} from "@/utility/recipeParser";
import {logDebug} from ".";
import {CanShareResult, Share} from "@capacitor/share";
import {useTasteBuddyStore} from "@/storage";

// types for recipe

/**
 * Item of a recipe
 * It can be an ingredient or a tool
 */
export class Item {
    _id?: string;
    _tmpId?: string;
    name: string;
    type: string;
    imgUrl: string;

    constructor(item?: Item) {
        // create a temporary id to identify the item in the store before it is saved
        this._id = item?._id
        if (this._id === undefined && item?._tmpId === undefined) {
            this._tmpId = item?._tmpId ?? `tmp${Date.now().toString(16)}${Math.random().toString(16).slice(2)}`
        }
        this.name = item?.name ?? 'New Item'
        this.type = item?.type ?? 'ingredient'
        this.imgUrl = item?.imgUrl ?? ''
    }

    /**
     * Initialize an item from a json object
     * This is done because the json object does not have the methods of the class
     *
     * @param json
     * @returns a new recipe
     */
    static fromJSON(json: Item): Item {
        const item = new Item()
        item._id = json._id
        // remove the temporary id
        delete item._tmpId
        item.name = json.name
        item.type = json.type
        item.imgUrl = json.imgUrl
        return item
    }

    /**
     * Add a new item to the store
     * @returns the item to allow chaining
     */
    public static newItem(): Item {
        return new Item()
    }

    /**
     * Add a new item to the store with a given name
     * @param name
     * @returns the item to allow chaining
     */
    public static newItemFromName(name?: string): Item {
        const item = new Item()
        item.name = name ?? 'New Item'
        return item
    }

    /**
     * Get the id of the item
     * @returns the id of the item
     * @throws an error if the id is undefined
     */
    public getId(): string {
        // if the id is undefined, throw an error
        if (this._id === undefined && this._tmpId === undefined) {
            throw new Error("item id is undefined")
        }
        return this._id ?? this._tmpId as string
    }

    /**
     * Update the item in the store
     * @param store
     * @returns the item to allow chaining
     */
    public update(store: any): this {
        store.updateItem(this)
        return this
    }

    /**
     * Save the item to the database
     * @param store
     * @returns the item to allow chaining
     */
    public save(store: any): this {
        // remove the temporary id
        store.saveItem(this)
        return this
    }

    /**
     * Delete the item from the database
     */
    public delete(): void {
        const store = useTasteBuddyStore()
        store.deleteItem(this)
    }

    /**
     * Narrow the item to an item
     * @param item
     */
    public narrow(item: Item): Item {
        return new Item(item)
    }
}

/**
 * StepItem of a recipe
 * It is an item with an amount and a unit
 * It is used in a step
 * This is done to make the item reusable
 */
export class StepItem extends Item {
    amount: number;
    servingAmount: number;
    unit: string;

    constructor(item?: Item) {
        super(item)
        this.amount = 1
        this.servingAmount = 1
        this.unit = 'pcs'
    }

    /**
     * Initialize an stepItem from a json object
     * This is done because the json object does not have the methods of the class
     *
     * @param json
     * @returns a new recipe
     */
    static fromJSON(json: StepItem): StepItem {
        const stepItem = new StepItem()
        stepItem.amount = json.amount
        stepItem.servingAmount = json.amount
        stepItem.unit = json.unit
        const store = useTasteBuddyStore()
        const item = store.getItemsAsMap[json._id ?? '']
        if (typeof item !== 'undefined') {
            stepItem._id = item._id
            stepItem.name = item.name
            stepItem.type = item.type
            stepItem.imgUrl = item.imgUrl
        } else {
            stepItem.name = json.name
            stepItem.type = json.type
        }
        return stepItem
    }

    /**
     * Update the item in the step
     * @param item
     */
    updateItem(item: Item): void {
        this._id = item._id
        this.name = item.name
        this.type = item.type
        this.imgUrl = item.imgUrl
    }
}

export type BakingStepInformation = {
    informationType: "baking";
    temperature: string;
    duration: string;
    bakingType: string;
}

export type AdditionalStepInformation = BakingStepInformation | { [key: string]: string }

/**
 * Step of a recipe
 * It is a step with a list of StepItems
 * It can have an image, a description and a preparation time for the step
 */
export class Step {
    items: StepItem[];
    imgUrl?: string;
    description: string;
    duration?: number;
    additional?: AdditionalStepInformation

    constructor() {
        this.items = [new StepItem()]
        this.imgUrl = ''
        this.description = 'New step description'
        this.duration = 0
    }

    /**
     * Initialize an stepItem from a json object
     * This is done because the json object does not have the methods of the class
     *
     * @param json
     * @returns a new recipe
     */
    static fromJSON(json: Step): Step {
        const item = new Step()
        item.items = json.items?.map(item => StepItem.fromJSON(item)) ?? []
        item.imgUrl = json.imgUrl
        item.description = json.description
        item.duration = json.duration
        item.additional = json.additional
        return item
    }

    /**
     * Create a step from a list of step items
     * @param stepItems
     * @param description
     * @returns a new step
     */
    public static fromStepItems(stepItems: StepItem[], description?: string): Step {
        const step = new Step()
        step.items = stepItems
        step.description = description ?? ''
        return step
    }

    /**
     * Generate a list of steps from a description
     * @param description
     * @returns a list of steps
     */
    public static fromDescription(description: string): Step[] {
        return descriptionToSteps(description)
    }

    /**
     * Get the short description of the recipe. It is the first two sentences of the description.
     * @returns the short description of the recipe
     */
    public getShortDescription(maxLength = 2): string {
        let shortDescription = this.description.split('.').slice(0, maxLength).join('.')
        const lastChar = shortDescription.charAt(shortDescription.length - 1)
        if (lastChar !== '.' && lastChar !== '?' && lastChar !== '!') {
            shortDescription += '.'
        }
        return shortDescription
    }

    /**
     * Get all unique items in the step
     * @returns a list of all items in the step
     */
    public getItems(): StepItem[] {
        return [...new Set(this.items)]
    }

    /**
     * Update the servings of the step
     * @param servings
     * @returns the step to allow chaining
     */
    public updateServings(servings = 1): this {
        this.items.forEach(item => {
            item.servingAmount = item.amount * servings
        })
        return this
    }
}

/**
 * Recipe
 * It is a recipe with a list of steps
 * It contains all the information about a recipe
 */
export class Recipe {
    _id?: string;
    _tmpId?: string;
    name: string;
    author: string;
    description: string;
    steps: Step[];
    props: {
        url?: string;
        imgUrl?: string;
        duration?: number;
        createdAt: Date;
        tags?: string[];
    };
    servings: number;
    isLiked: boolean;

    constructor() {
        // create a temporary id to identify the recipe in the store before it is saved
        this._tmpId = `tmp${Date.now().toString(16)}${Math.random().toString(16).slice(2)}`
        this.name = 'New Recipe'
        this.author = ''
        this.description = ''
        this.props = {
            url: '',
            imgUrl: '',
            duration: 0,
            createdAt: new Date(),
            tags: [],
        }
        this.steps = [new Step()]
        this.servings = 1
        this.isLiked = false;
    }

    /**
     * Initialize a recipe from a json object
     * This is done because the json object does not have the methods of the class
     *
     * @param json
     * @returns a new recipe
     */
    public static fromJSON(json: Recipe): Recipe {
        const recipe = new Recipe()
        recipe._id = json._id
        delete recipe._tmpId
        // if the id is undefined, throw an error
        if (recipe._id === undefined) {
            throw new Error("recipe id is undefined")
        }
        recipe.name = json.name
        recipe.author = json.author
        recipe.description = json.description
        recipe.steps = json.steps?.map(step => Step.fromJSON(step)) ?? [new Step()]
        // props
        recipe.props.imgUrl = json.props.imgUrl
        recipe.props.tags = json.props.tags
        recipe.props.duration = json.props.duration
        recipe.props.createdAt = new Date(json.props.createdAt)
        return recipe
    }

    /**
     * Initialize a new recipe with a temporary id
     * @returns a new recipe with a temporary id
     */
    public static newRecipe(): Recipe {
        return new Recipe()
    }

    /**
     * Save the recipe to the database by its id
     * @param store
     * @param id
     */
    public static saveById(store: any, id: string): void {
        logDebug('saveById', id)
        store.saveRecipeById(id)
    }

    /**
     * Get the id of the recipe
     * @returns the id of the recipe
     * @throws an error if the id is undefined
     */
    public getId(): string {
        // if the id is undefined, throw an error
        if (this._id === undefined && this._tmpId === undefined) {
            throw new Error("recipe id is undefined")
        }
        return this._id ?? this._tmpId as string
    }

    /**
     * Get the duration of the recipe. It is the sum of the duration of all steps.
     * @returns the duration of the recipe
     */
    public getDuration(): number {
        return this.steps.reduce((acc, step) => acc + (step.duration ?? 0), 0)
    }

    /**
     * Get the short description of the recipe. It is the first two sentences of the description.
     * @returns the short description of the recipe
     */
    public getShortDescription(): string {
        let shortDescription = this.description.split('.').slice(0, 2).join('.')
        const lastChar = shortDescription.charAt(shortDescription.length - 1)
        if (lastChar !== '.' && lastChar !== '?' && lastChar !== '!') {
            shortDescription += '.'
        }
        return shortDescription
    }

    /**
     * Updates the recipe in the store
     * @param store
     * @returns the recipe to allow chaining
     */
    public update(store: any): this {
        logDebug('update', this.getId())
        store.updateRecipe(this)
        return this
    }

    /**
     * Save the recipe to the database
     * @param store
     * @returns the id of the recipe
     */
    public save(store: any) {
        logDebug('save', this.getId())
        return store.saveRecipe(this)
    }

    /**
     * Delete the recipe from the database
     * @param store
     */
    public delete() {
        const store = useTasteBuddyStore()
        logDebug('delete', this.getId())
        return store.deleteRecipe(this)
    }

    /**
     * Add a step to the recipe
     * @param step
     * @param stepIndex
     * @returns the recipe to allow chaining
     */
    public addStep(step?: Step, stepIndex?: number): this {
        const _step: Step = step ?? new Step()

        if (stepIndex !== undefined) {
            // insert the step at the given index
            this.steps.splice(stepIndex + 1, 0, _step)
        } else {
            // add the step to the end
            this.steps.push(_step)
        }
        return this
    }

    /**
     * Add multiple steps to the recipe
     * @param steps
     * @returns the recipe to allow chaining
     */
    public addSteps(steps: Step[]): this {
        this.steps.push(...steps)
        return this
    }

    /**
     * Remove a step from the recipe
     * @param index
     * @returns the recipe to allow chaining
     */
    public removeStep(index: number): this {
        this.steps.splice(index, 1)
        return this
    }

    /**
     * Add an item to a step
     * @param stepIndex index of the step
     * @param itemIndex index of the item
     * @param item the item to add
     * @returns the recipe and the item
     */
    public addItem(stepIndex?: number, itemIndex?: number, item?: Item): { item: Item, recipe: Recipe } {
        item = item ?? new Item();
        const stepItem = new StepItem();

        if (stepIndex === undefined) {
            // add a new step if no step is specified
            this.steps[this.steps.length - 1].items.push(stepItem);
        } else if (itemIndex === undefined) {
            // add a new item to the step if no item is specified
            this.steps[stepIndex].items.push(stepItem);
        } else {
            // update the item at the specified index
            this.steps[stepIndex].items[itemIndex] = new StepItem(item);
        }
        return {item, recipe: this};
    }

    /**
     * Get all unique items in the recipe
     * @returns a list of all items in the recipe
     */
    public getItems(sorted = false): StepItem[] {
        // use a Set to remove duplicates: https://stackoverflow.com/a/14438954
        // use flatMap to get all items in the recipe
        const items: StepItem[] = Object.values(Object.assign({}, ...this.steps
            .flatMap((step: Step) => step.getItems())
            .map(stepItem => ({[stepItem.getId()]: stepItem}))
        ))
        const uniqueItems: { [key: string]: StepItem } = {}
        items.forEach((item: StepItem) => {
            uniqueItems[item.getId()] = item
        })
        const result = Object.values(uniqueItems)
        if (sorted) {
            result.sort((a, b) => a.name.localeCompare(b.name))
        }
        console.log(result)
        return result
    }

    /**
     * Add a tag to the recipe
     * @param tag
     * @returns the recipe to allow chaining
     */
    public addTag(tag: string): this {
        if (this.props.tags === undefined) {
            // initialize the tags array if it is undefined
            this.props.tags = []
        }
        this.props.tags.push(tag)
        return this
    }

    /**
     * Share the recipe with buddies
     * This will open the share dialog of the device
     * @returns a promise that resolves when the share dialog is closed
     */
    public async share() {
        return Share.canShare().then((canShare: CanShareResult) => {
            if (!canShare.value) {
                return
            }

            try {
                return Share.share({
                    title: 'Share with your recipe with buddies',
                    text: `Check out this recipe for ${this.name} on Taste Buddy!`,
                    url: '#/' + this.route(),
                    dialogTitle: 'Share with buddies',
                })
            } catch (e) {
                console.log('sharing aborted')
            }
        })
    }

    /**
     * Get the route to the recipe
     */
    public route(): string {
        return '/recipe/s/' + this.getId()
    }

    /**
     * Update the servings of the recipe
     * @param servings
     */
    public updateServings(servings: number) {
        this.servings = servings
        this.steps.forEach(step => {
            step.updateServings(servings)
        })
    }

    /**
     * Like or unlike the recipe
     */
    public toggleLike() {
        const store = useTasteBuddyStore()
        this.isLiked = !this.isLiked
        store.updateLike(this)
    }
}

// types for suggestion
export type RecipeSuggestionQuery = {
    item_query: {
        id: string;
        name: string;
        exclude: boolean;
    }[];
    city?: string;
}


export class RecipeSuggestion {

    recipe_id: string;
    recipe?: Recipe;
    recipe_price?: number;
    market_for_price?: Market;
    missing_items?: {
        item_id: string;
        item?: Item;
        amount: number;
        price?: number;
    }[]

    constructor() {
        this.recipe_id = ''
        this.recipe_price = 0
        this.market_for_price = undefined
        this.missing_items = []
    }

    /**
     * Initialize a recipe suggestion from a json object
     * This is done because the json object does not have the methods of the class
     *
     * @param json
     * @returns a new suggestion
     */
    public static fromJSON(json: RecipeSuggestion): RecipeSuggestion {
        const suggestion = new RecipeSuggestion()
        const store = useTasteBuddyStore()
        suggestion.recipe_id = json.recipe_id
        suggestion.recipe = store.getRecipesAsMap[json.recipe_id]
        suggestion.recipe_price = json.recipe_price
        suggestion.market_for_price = json.market_for_price
        suggestion.missing_items = json.missing_items
        suggestion.missing_items = suggestion.missing_items?.map((missing_item) => {
            return {
                item_id: missing_item.item_id,
                item: store.getItemsAsMap[missing_item.item_id],
                amount: missing_item.amount,
                price: missing_item.price
            }
        })
        return suggestion
    }

    /**
     * Suggest recipes based on the given query
     * @param store
     * @param itemIds
     * @param city
     * @returns a promise that resolves to a list of recipe suggestions
     */
    public static suggestRecipes(store: any, itemIds: string[], city?: string): Promise<RecipeSuggestion[]> {
        const query: RecipeSuggestionQuery = {
            item_query: itemIds.map(id => {
                return {
                    id,
                    name: '',
                    exclude: false
                }
            }),
            city: city ?? undefined
        }

        return store.fetchRecipeSuggestions(query)
    }

    /**
     * Get the recipe of the suggestion
     */
    public getRecipe(): Recipe {
        return this.recipe ?? new Recipe()
    }

    public getMissingItems(): Item[] {
        return this.missing_items?.map(missing_item => missing_item.item ?? new Item()) ?? []
    }
}


// types for discounts

/**
 * A discount represents a discount on a product
 * It is a generic representation that is created by the backend based on the data from the different markets
 * The id is the id of the discount in the database
 */
export type Discount = {
    _id: string;
    title: string;
    price: string;
    imageUrl: string;
    validUntil: number;
    internalMarketId: string;
    marketName: string;
    marketLocation: string;
}

/**
 * A market represents a market where a product is sold
 * It is a generic representation that is created by the backend based on the data from the different markets
 * The id is the id of the market in the database
 */
export type Market = {
    _id: string;
    distributor: string;
    distributorSpecificId: string;
    name: string;
    city: string;
    location: string;
}